#include<bits/stdc++.h>
using namespace std;
int t;
int main() {
	cin>>t;
	while(t--) {
		string a,b;
		cin>>a>>b;
		if(a.length()<b.length())
			swap(a,b);
			
		if(a.length()==b.length()) {
			int cnt=0;
			for(int i=0;i<a.length();i++) {
				if(a[i]!=b[i]) {
					cnt++;
				}
			}
			if(cnt<=1)
				cout<<"similar"<<endl;
			else
				cout<<"not similar"<<endl;
		}
		else if(a.length()-b.length()==1) {
			int cnt=0,flag=0;
			for(int i=0;i<b.length();i++)  {
				if(a[i+cnt]!=b[i])
					cnt=1;
				if(cnt&&a[i+cnt]!=b[i]) {
					cout<<"not similar"<<endl;
					flag=1;
					break;
				}
			}
			if(flag==0)
				cout<<"similar"<<endl;
		}
		else {
			cout<<"not similar"<<endl;
		}
	}
	return 0;
}
